"""matplotlib.axis — Axis classes."""

from matplotlib.artist import Artist


class Axis(Artist):
    OFFSETTEXTPAD = 3

    def __init__(self, axes, **kwargs):
        super().__init__()
        self.axes = axes
        self.major = None
        self.minor = None
        self._label = None
        self.isDefault_label = True

    def set_major_formatter(self, formatter): pass
    def set_minor_formatter(self, formatter): pass
    def set_major_locator(self, locator): pass
    def set_minor_locator(self, locator): pass
    def get_major_formatter(self): return None
    def get_minor_formatter(self): return None
    def get_major_locator(self): return None
    def get_minor_locator(self): return None
    def get_major_ticks(self): return []
    def get_minor_ticks(self): return []
    def get_ticklabels(self, minor=False): return []
    def set_ticklabels(self, labels, **kwargs): pass
    def get_tick_params(self): return {}
    def set_tick_params(self, **kwargs): pass
    def set_ticks(self, ticks, labels=None, **kwargs): pass
    def get_ticks(self): return []
    def set_label_text(self, label, **kwargs): pass
    def get_label_text(self): return ''
    def set_visible(self, v): pass
    def set_ticks_position(self, position): pass
    def set_label_position(self, position): pass
    def grid(self, visible=None, which='major', **kwargs): pass
    def set_inverted(self, inverted): pass
    def get_inverted(self): return False
    def set_scale(self, value, **kwargs): pass
    def get_scale(self): return 'linear'
    def get_view_interval(self): return (0, 1)
    def set_view_interval(self, vmin, vmax, ignore=False): pass
    def get_data_interval(self): return (0, 1)
    def set_data_interval(self, vmin, vmax, ignore=False): pass


class XAxis(Axis):
    __name__ = 'xaxis'
    axis_name = 'x'


class YAxis(Axis):
    __name__ = 'yaxis'
    axis_name = 'y'


class Tick(Artist):
    def __init__(self, axes, loc, **kwargs):
        super().__init__()
        self.axes = axes
        self._loc = loc
    def get_loc(self): return self._loc
    def set_label1(self, s): pass
    def set_label2(self, s): pass
    def get_pad(self): return 0
    def set_pad(self, val): pass
